#include <iostream>
#include <string>
#include <vector>
#include <fstream>
#include <cstdlib> // For system()

std::string read_file(const std::string& filename) {
    std::ifstream ifs(filename);
    std::string content((std::istreambuf_iterator<char>(ifs)),
                           (std::istreambuf_iterator<char>()));
    ifs.close();
    return content;
}

void run_test_case(const std::string& input, const std::string& expected_output) {
    std::ofstream input_file("temp_input.txt");
    input_file << input;
    input_file.close();

    // Compile and run the user's program
    // Assuming the user's code is in 'solution.cpp' and compiled to 'a.out'
    // This driver assumes the compilation step happens externally or fails for syntax errors.
    // For correctness, it would typically run a pre-compiled binary.
    // Here, we simulate by running 'a.out' which would exist if compilation succeeded.
    system("./a.out < temp_input.txt > temp_output.txt 2>&1"); // Redirect stderr too

    std::string actual_output = read_file("temp_output.txt");

    std::cout << "--- Test Case ---\n";
    std::cout << "Input:\n" << input;
    std::cout << "Expected Output:\n" << expected_output;
    std::cout << "Actual Output:\n" << actual_output;

    if (actual_output.find(expected_output) != std::string::npos && !expected_output.empty()) {
        std::cout << "Test Passed! (Output contains expected)\n\n";
    } else if (actual_output.empty() && expected_output.empty()) {
        std::cout << "Test Passed! (Both empty)\n\n";
    } else {
        std::cout << "Test Failed!\n\n";
    }

    system("rm -f temp_input.txt temp_output.txt"); // Clean up temporary files
}

int main() {
    // This driver is illustrative. In a real testing environment,
    // 'run_test_case' would be called for each entry in the 'test_cases' array.
    // For a Syntax Error, compilation will fail, and 'a.out' won't be created.
    // The testing system would detect this prior to running tests.
    std::cout << "Driver for syntax error: Compilation is expected to fail. If 'a.out' exists, it's from a previous successful build.\n";
